@@ -108,10 +108,10 @@ mod tests {
     fn ctrl_c_not_available() {
         init_test("ctrl_c_not_available");
         let available = is_available();
-        #[cfg(unix)]
-        crate::assert_with_log!(available, "available on unix", true, available);
